// The correct solution is to use the Math.max function to calculate the maximum height of the child elements.
function calculateHeight(element, children) {
  if (children.length === 0) return 0;
  return Math.max(...children.map(child => child.height));
}

solutions.python:
class Solution:
  def calculate_height(self, element, children):
    if not children: return 0
    return max(child.height for child in children)
